using System;
using System.Threading.Tasks;
using Azure.Identity;
using Azure.ResourceManager;
using Azure.ResourceManager.Resources;
using Azure.ResourceManager.StorageMover;
using Azure.ResourceManager.StorageMover.Models;
using NUnit.Framework;

namespace Azure.ResourceManager.StorageMover.Samples
{
    public class Sample1_StorageMoverBasics
    {
        [Test]
        [Ignore("Only run in live tests")]
        public async Task CreateStorageMover()
        {
            #region Snippet:StorageMover_CreateOrUpdate
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            ResourceGroupResource resourceGroup = await subscription.GetResourceGroups().GetAsync("myResourceGroup");

            StorageMoverCollection storageMoverCollection = resourceGroup.GetStorageMovers();
            StorageMoverData data = new StorageMoverData(new Azure.Core.AzureLocation("eastus"));
            ArmOperation<StorageMoverResource> lro = await storageMoverCollection.CreateOrUpdateAsync(
                WaitUntil.Completed,
                "myStorageMover",
                data);
            StorageMoverResource storageMover = lro.Value;
            Console.WriteLine($"Created StorageMover: {storageMover.Data.Name}");
            #endregion
        }

        [Test]
        [Ignore("Only run in live tests")]
        public async Task CreateBlobEndpoint()
        {
            #region Snippet:StorageMover_CreateBlobEndpoint
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            ResourceGroupResource resourceGroup = await subscription.GetResourceGroups().GetAsync("myResourceGroup");
            StorageMoverResource storageMover = await resourceGroup.GetStorageMovers().GetAsync("myStorageMover");

            StorageMoverEndpointCollection endpointCollection = storageMover.GetStorageMoverEndpoints();
            StorageMoverEndpointData endpointData = new StorageMoverEndpointData(
                new AzureStorageBlobContainerEndpointProperties(
                    storageAccountResourceId: new Azure.Core.ResourceIdentifier("/subscriptions/{subscriptionId}/resourceGroups/myRG/providers/Microsoft.Storage/storageAccounts/myStorageAccount"),
                    blobContainerName: "mycontainer"));

            ArmOperation<StorageMoverEndpointResource> lro = await endpointCollection.CreateOrUpdateAsync(
                WaitUntil.Completed,
                "myBlobEndpoint",
                endpointData);
            StorageMoverEndpointResource endpoint = lro.Value;
            Console.WriteLine($"Created endpoint: {endpoint.Data.Name}");
            #endregion
        }

        [Test]
        [Ignore("Only run in live tests")]
        public async Task CreateJobDefinitionWithSchedule()
        {
            #region Snippet:StorageMover_CreateJobDefinitionWithSchedule
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            ResourceGroupResource resourceGroup = await subscription.GetResourceGroups().GetAsync("myResourceGroup");
            StorageMoverResource storageMover = await resourceGroup.GetStorageMovers().GetAsync("myStorageMover");
            StorageMoverProjectResource project = await storageMover.GetStorageMoverProjects().GetAsync("myProject");

            JobDefinitionData jobDefData = new JobDefinitionData(
                copyMode: StorageMoverCopyMode.Additive)
            {
                SourceName = "myNfsEndpoint",
                TargetName = "myBlobEndpoint",
                AgentName = "myAgent",
                // New in 1.4.0: configure a recurring schedule
                Schedule = new StorageMoverScheduleInfo
                {
                    Frequency = StorageMoverScheduleFrequency.Daily,
                    // ScheduleTime = ...
                },
                // New in 1.4.0: enable data integrity validation
                DataIntegrityValidation = StorageMoverDataIntegrityValidation.Enabled,
                // New in 1.4.0: preserve permissions
                IsPermissionsPreserved = true,
            };

            ArmOperation<JobDefinitionResource> lro = await project.GetJobDefinitions().CreateOrUpdateAsync(
                WaitUntil.Completed,
                "myJobDefinition",
                jobDefData);
            JobDefinitionResource jobDefinition = lro.Value;
            Console.WriteLine($"Created job definition: {jobDefinition.Data.Name}");
            #endregion
        }

        [Test]
        [Ignore("Only run in live tests")]
        public async Task StartJobRun()
        {
            #region Snippet:StorageMover_StartJobRun
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            ResourceGroupResource resourceGroup = await subscription.GetResourceGroups().GetAsync("myResourceGroup");
            StorageMoverResource storageMover = await resourceGroup.GetStorageMovers().GetAsync("myStorageMover");
            StorageMoverProjectResource project = await storageMover.GetStorageMoverProjects().GetAsync("myProject");
            JobDefinitionResource jobDefinition = await project.GetJobDefinitions().GetAsync("myJobDefinition");

            // Start a new job run
            ArmOperation<JobDefinitionResource> startLro = await jobDefinition.StartJobAsync(WaitUntil.Started);

            // List all runs for this job definition
            await foreach (JobRunResource run in jobDefinition.GetJobRuns().GetAllAsync())
            {
                Console.WriteLine($"Job run {run.Data.Name}: status={run.Data.Status}");
            }
            #endregion
        }
    }
}
```

Each `#region Snippet:<Name>` tag corresponds to the `C# Snippet:<Name>` placeholder inserted in the README in Step 1.

